+/// console.countReset(label) - Reset counter to 0
+fn consoleCountReset(ctx: ?*qjs.JSContext, _: qjs.JSValue, argc: c_int, argv: [*c]qjs.JSValue) callconv(.c) qjs.JSValue {
+    const default_label = "default";
